class Solution {
public:
    bool isRationalEqual(string s, string t) {
        return parse(s) == parse(t);
    }
private:
    long double parse(const string& s) {
        size_t dot = s.find('.');
        string intPart = (dot == string::npos) ? s : s.substr(0, dot);
        long double res = stol(intPart);
        if (dot == string::npos) return res;

        string fracPart = s.substr(dot + 1);
        size_t open = fracPart.find('(');
        string nonRep = (open == string::npos) ? fracPart : fracPart.substr(0, open);
        string rep = (open == string::npos) ? "" : fracPart.substr(open + 1, fracPart.size() - open - 2);

        long double denom = 1;
        for (char c : nonRep) {
            res += (c - '0') / (denom *= 10);
        }

        if (!rep.empty()) {
            long double repVal = 0;
            long double repDenom = 1;
            for (char c : rep) {
                repVal = repVal * 10 + (c - '0');
                repDenom *= 10;
            }
            res += repVal / (denom * (repDenom - 1));
        }
        return res;
    }
};
